+router.patch('/me', async (req, res, next) => {
+  try {
+    const result = await profileService.update(req.user.id, req.body, req.body.version);
+    res.json(result);
+  } catch (err) {
+    if (err instanceof VersionConflictError) {
+      res.status(409).json({ error: 'version_conflict', current: err.current });
+      return;
+    }
+    next(err);
+  }
+});

+export class VersionConflictError extends Error {
+  constructor(public current: ProfileRow) { super('version_conflict'); }
+}
+
+export async function update(id: string, patch: ProfilePatch, expected: number) {
+  return db.tx(async (tx) => {
+    const row = await tx.profile.findById(id);
+    if (row.version !== expected) throw new VersionConflictError(row);
+    return tx.profile.update(id, { ...patch, version: row.version + 1 });
+  });
+}
